      if (i < phases.length - 1) { s.addText("→", { x: x + boxW, y: 2.2, w: 0.6, h: boxH, fontFace: D.b, fontSize: 28, color: D.accent, bold: true, align: "center", margin: 0, valign: "middle" }); }
